import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { useAuth } from '../context/AuthContext';

function Dashboard() {
  const [members, setMembers] = useState([]);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [role, setRole] = useState('Member');
  const [error, setError] = useState('');
  const { logout, user } = useAuth();

  useEffect(() => {
    fetchMembers();
  }, []);

  const fetchMembers = async () => {
    try {
      const response = await axios.get('/members');
      setMembers(response.data);
    } catch (err) {
      setError('Failed to fetch members.');
    }
  };

  const handleAddMember = async (e) => {
    e.preventDefault();
    setError('');
    try {
      await axios.post('/members', { name, email, role });
      setName('');
      setEmail('');
      setRole('Member');
      fetchMembers(); // Refresh member list
    } catch (err) {
      setError('Failed to add member. Email might already exist.');
    }
  };

  const handleDeleteMember = async (memberId) => {
    try {
      await axios.delete(`/members/${memberId}`);
      fetchMembers(); // Refresh member list
    } catch (err) {
      setError('Failed to delete member.');
    }
  };

  return (
    <div className="container">
      <h2>Dashboard</h2>
      {user && <p>Welcome, {user.email}!</p>}
      <button onClick={logout} style={{width: 'auto', padding: '10px 20px', marginBottom: '20px'}}>Logout</button>
      
      <hr />

      <h3>Add New Member</h3>
      {error && <p className="error">{error}</p>}
      <form onSubmit={handleAddMember} style={{marginBottom: '2rem'}}>
        <input
          type="text"
          placeholder="Name"
          value={name}
          onChange={(e) => setName(e.target.value)}
          required
        />
        <input
          type="email"
          placeholder="Email"
          value={email}
          onChange={(e) => setEmail(e.target.value)}
          required
        />
        <input
          type="text"
          placeholder="Role"
          value={role}
          onChange={(e) => setRole(e.target.value)}
        />
        <button type="submit">Add Member</button>
      </form>

      <h3>Members List</h3>
      <ul style={{listStyle: 'none', padding: 0}}>
        {members.map(member => (
          <li key={member.id} style={{display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '10px', borderBottom: '1px solid #eee'}}>
            <span>{member.name} ({member.email}) - {member.role}</span>
            <button onClick={() => handleDeleteMember(member.id)} style={{width: 'auto', backgroundColor: '#f44336'}}>Delete</button>
          </li>
        ))}
      </ul>
    </div>
  );
}

export default Dashboard;
